const chalk = require('chalk');

/**
 * Shows help information with all available Dbcube CLI commands
 */
async function showHelp() {
    try {
        console.log(`\n${chalk.green('🚀 Dbcube CLI - Command Reference')}`);
        console.log(`${chalk.gray('A powerful database toolkit for modern applications')}\n`);
        
        console.log(`${chalk.cyan.bold('USAGE:')}`);
        console.log(`  ${chalk.white('npx dbcube')} ${chalk.yellow('<command>')} ${chalk.gray('[options]')}\n`);

        console.log(`${chalk.cyan.bold('PROJECT COMMANDS:')}`);
        console.log(`  ${chalk.yellow('init')}                      ${chalk.white('Scaffold a new DBCube project (config + dbcube/ + example)')}`);
        console.log(`  ${chalk.yellow('generate')}                  ${chalk.white('Generate TypeScript types from .table.cube files')}`);
        console.log(`  ${chalk.yellow('validate')}                  ${chalk.white('Validate every .cube file without executing (CI-friendly)')}`);
        console.log(`  ${chalk.yellow('doctor')}                    ${chalk.white('Diagnose config, binaries, and database connectivity')}`);
        console.log(`  ${chalk.yellow('dev')}                       ${chalk.white('Watch mode: .cube changes apply automatically')}\n`);

        console.log(`${chalk.cyan.bold('DATABASE COMMANDS:')}`);
        console.log(`  ${chalk.yellow('database:create')}           ${chalk.white('Create a new database with interactive setup')}`);
        console.log(`  ${chalk.yellow('run database:create')}       ${chalk.white('Alternative syntax for database creation')}`);
        console.log(`  ${chalk.yellow('run database:create:config')} ${chalk.white('Add database configuration only')}`);
        console.log(`  ${chalk.yellow('run database:create:physical')} ${chalk.white('Create physical database using existing config')}\n`);
        
        console.log(`${chalk.cyan.bold('TABLE COMMANDS:')}`);
        console.log(`  ${chalk.yellow('run table:fresh')}           ${chalk.white('Drop and recreate all tables from .cube files')}`);
        console.log(`  ${chalk.yellow('run table:refresh')}         ${chalk.white('Refresh table structures without dropping data')}`);
        console.log(`  ${chalk.yellow('run table:alter')}           ${chalk.white('Apply PENDING .alter.cube migrations (tracked)')}`);
        console.log(`  ${chalk.gray('  Options:')} --dry-run ${chalk.gray('(print SQL only)')} · --all ${chalk.gray('(ignore history)')}\n`);

        console.log(`${chalk.cyan.bold('MIGRATION COMMANDS:')}`);
        console.log(`  ${chalk.yellow('migrate:status')}            ${chalk.white('Show applied and pending migrations')}`);
        console.log(`  ${chalk.yellow('migrate:rollback')}          ${chalk.white('Revert the last applied migration batch')}`);
        console.log(`  ${chalk.yellow('run pull [database]')}       ${chalk.white('Generate .table.cube files FROM an existing database')}\n`);
        
        console.log(`${chalk.cyan.bold('TRIGGER COMMANDS:')}`);
        console.log(`  ${chalk.yellow('run trigger:fresh')}         ${chalk.white('Recreate all database triggers from .cube files')}\n`);
        
        console.log(`${chalk.cyan.bold('SEEDER COMMANDS:')}`);
        console.log(`  ${chalk.yellow('run seeder:add')}            ${chalk.white('Add test data from seeder .cube files')}\n`);

        console.log(`${chalk.cyan.bold('BINARY MANAGEMENT:')}`);
        console.log(`  ${chalk.yellow('update')}                    ${chalk.white('Check and update binaries to latest version')}`);
        console.log(`  ${chalk.yellow('run download')}              ${chalk.white('Download binaries interactively')}`);
        console.log(`  ${chalk.yellow('run download <engine>')}     ${chalk.white('Download specific engine (latest version)')}`);
        console.log(`  ${chalk.yellow('run download <engine> <ver>')} ${chalk.white('Download specific engine version')}`);
        console.log(`  ${chalk.gray('  Engines:')} query-engine, schema-engine\n`);

        console.log(`${chalk.cyan.bold('UTILITY COMMANDS:')}`);
        console.log(`  ${chalk.yellow('version, --version, -v')}    ${chalk.white('Show CLI version information')}`);
        console.log(`  ${chalk.yellow('help, --help, -h')}          ${chalk.white('Show this help information')}\n`);
        
        console.log(`${chalk.cyan.bold('FILE STRUCTURE:')}`);
        console.log(`  ${chalk.gray('dbcube/')}`);
        console.log(`  ${chalk.gray('├── *.table.cube')}             ${chalk.white('Table schema definitions')}`);
        console.log(`  ${chalk.gray('├── *.alter.cube')}             ${chalk.white('ALTER TABLE migrations and changes')}`);
        console.log(`  ${chalk.gray('├── *.seeder.cube')}            ${chalk.white('Test data and seeders')}`);
        console.log(`  ${chalk.gray('├── *.trigger.cube')}           ${chalk.white('Database triggers')}`);
        console.log(`  ${chalk.gray('└── dbcube.config.js')}         ${chalk.white('Database configuration file')}\n`);
        
        console.log(`${chalk.cyan.bold('EXAMPLES:')}`);
        console.log(`  ${chalk.gray('# Setup a new database')}`);
        console.log(`  ${chalk.white('npx dbcube database:create')}\n`);
        
        console.log(`  ${chalk.gray('# Recreate all tables')}`);
        console.log(`  ${chalk.white('npx dbcube run table:fresh')}\n`);
        
        console.log(`  ${chalk.gray('# Apply ALTER TABLE changes (.alter.cube)')}`);
        console.log(`  ${chalk.white('npx dbcube run table:alter')}\n`);

        console.log(`  ${chalk.gray('# Add seed data')}`);
        console.log(`  ${chalk.white('npx dbcube run seeder:add')}\n`);

        console.log(`  ${chalk.gray('# Download a specific binary version')}`);
        console.log(`  ${chalk.white('npx dbcube run download query-engine v3.1.1')}\n`);

        console.log(`  ${chalk.gray('# Check and update binaries if needed')}`);
        console.log(`  ${chalk.white('npx dbcube update')}\n`);
        
        console.log(`${chalk.cyan.bold('CONFIGURATION:')}`);
        console.log(`  ${chalk.white('Create a')} ${chalk.yellow('dbcube.config.js')} ${chalk.white('file in your project root (or run')} ${chalk.yellow('npx dbcube init')}${chalk.white('):')}`);
        console.log(`  ${chalk.gray("module.exports = function (config) {")}`);
        console.log(`  ${chalk.gray('  config.set({')}`);
        console.log(`  ${chalk.gray('    databases: {')}`);
        console.log(`  ${chalk.gray('      myapp: {')}`);
        console.log(`  ${chalk.gray('        type: "sqlite", // mysql, postgres, sqlite, mongodb')}`);
        console.log(`  ${chalk.gray('        config: { DATABASE: process.env.DBCUBE_MYAPP_DATABASE }')}`);
        console.log(`  ${chalk.gray('      }')}`);
        console.log(`  ${chalk.gray('    }')}`);
        console.log(`  ${chalk.gray('  });')}`);
        console.log(`  ${chalk.gray('};')}\n`);
        
        console.log(`${chalk.cyan.bold('MORE INFO:')}`);
        console.log(`  ${chalk.white('Documentation:')} ${chalk.blue('https://github.com/Dbcube/query-builder')}`);
        console.log(`  ${chalk.white('Issues:')} ${chalk.blue('https://github.com/Dbcube/query-builder/issues')}\n`);
        
    } catch (error) {
        console.error('❌ Error showing help:', error.message);
        process.exit(1);
    }
}

// Ejecutar función
showHelp().catch(error => {
    console.error('Error fatal:', error);
    process.exit(1);
});